const stats = $('DB: Yesterday Analytics').first().json;
const brands = $('DB: Top Brands Yesterday').all();

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const dateStr = yesterday.toLocaleDateString('ru-RU', { day: '2-digit', month: '2-digit', year: 'numeric' });

// GMV delta arrow
const delta = parseFloat(stats.gmv_delta_pct || 0);
const deltaStr = delta >= 0 ? `📈 +${delta}%` : `📉 ${delta}%`;

// Refund rate color
const refundRate = parseFloat(stats.refund_rate_pct || 0);
const refundEmoji = refundRate > 10 ? '🔴' : refundRate > 5 ? '🟡' : '🟢';

// Build brand table
let brandLines = '';
if (brands.length > 0) {
  brandLines = '\n\n*🎮 Топ брендов:*\n';
  brands.forEach((b, i) => {
    const medals = ['🥇', '🥈', '🥉', '4️⃣', '5️⃣'];
    brandLines += `${medals[i]} ${b.json.brand}: ${b.json.sales} продаж | €${b.json.revenue_eur}\n`;
  });
} else {
  brandLines = '\n\n_Продаж вчера не было_';
}

// Pending moderation warning
const pendingMod = parseInt(stats.pending_moderation_count || 0);
let moderationAlert = '';
if (pendingMod > 0) {
  moderationAlert = `\n\n⏳ *На модерации:* ${pendingMod} товаров — нужна проверка!`;
}

const message = `🌅 *Gaming Goods — Daily Brief*\n${dateStr}\n\n` +
  `💰 *GMV:* €${stats.gmv_eur || '0.00'} ${deltaStr}\n` +
  `   (вчера: €${stats.prev_gmv_eur || '0.00'})\n\n` +
  `✅ *Заказов завершено:* ${stats.orders_completed || 0}\n` +
  `${refundEmoji} *Возвратов:* ${stats.orders_refunded || 0} (${stats.refund_rate_pct || 0}%)\n` +
  `🛒 *Брошено:* ${stats.orders_abandoned || 0} заказов\n\n` +
  `👥 *Покупателей:* ${stats.unique_buyers || 0}\n` +
  `🏪 *Продавцов активных:* ${stats.active_sellers || 0}\n` +
  `📦 *Новых товаров:* ${stats.new_products_listed || 0}\n\n` +
  `🏆 *Топ товар:* ${stats.top_product} (${stats.top_product_sales} продаж)` +
  brandLines +
  moderationAlert;

return [{ json: { message } }];

